```typescript
// Core interfaces
interface Message {
  payload: unknown;
  metadata: Record<string, unknown>;
}

interface Transformation {
  readonly name: string;
  apply(msg: Message): Message;
}

// Registry for runtime plugin management
type TransformationFactory = () => Transformation;

interface Registry {
  register(name: string, factory: TransformationFactory): void;
  unregister(name: string): boolean;
  get(name: string): Transformation | undefined;
  list(): string[];
}

function createRegistry(): Registry {
  const factories = new Map<string, TransformationFactory>();

  return {
    register(name: string, factory: TransformationFactory): void {
      if (factories.has(name)) {
        throw new Error(`Transformation '${name}' already registered`);
      }
      factories.set(name, factory);
    },

    unregister(name: string): boolean {
      return factories.delete(name);
    },

    get(name: string): Transformation | undefined {
      const factory = factories.get(name);
      return factory?.();
    },

    list(): string[] {
      return Array.from(factories.keys());
    }
  };
}

// Concrete transformations (Strategy implementations)
const enrichTransformation: Transformation = {
  name: 'enrich',
  apply(msg: Message): Message {
    return {
      ...msg,
      payload: { ...(msg.payload as object), enriched: true, timestamp: Date.now() },
      metadata: { ...msg.metadata, processedBy: 'enrich' }
    };
  }
};

const normalizeTransformation: Transformation = {
  name: 'normalize',
  apply(msg: Message): Message {
    const normalized = typeof msg.payload === 'string' 
      ? msg.payload.toLowerCase().trim() 
      : msg.payload;
    return { ...msg, payload: normalized };
  }
};

const validateTransformation: Transformation = {
  name: 'validate',
  apply(msg: Message): Message {
    if (!msg.payload) {
      throw new Error('Validation failed: empty payload');
    }
    return { ...msg, metadata: { ...msg.metadata, validated: true } };
  }
};

// Pipeline with metadata-driven dispatch
interface PipelineConfig {
  defaultTransformation?: string;
  fallback?: Transformation;
}

function createPipeline(registry: Registry, config: PipelineConfig = {}): (msg: Message) => Message {
  const { defaultTransformation = 'normalize', fallback } = config;

  return (msg: Message): Message => {
    const type = msg.metadata.transformationType as string ?? defaultTransformation;
    const transformer = registry.get(type);

    if (!transformer) {
      if (fallback) {
        return fallback.apply(msg);
      }
      console.warn(`Unknown transformation type: '${type}', using passthrough`);
      return msg;
    }

    return transformer.apply(msg);
  };
}

// Pipeline with chaining support
function createChainedPipeline(
  registry: Registry,
  transformations: string[]
): (msg: Message) => Message {
  return (msg: Message): Message => {
    return transformations.reduce((acc, name) => {
      const transformer = registry.get(name);
      return transformer ? transformer.apply(acc) : acc;
    }, msg);
  };
}

// === Usage Example ===

// Create and populate registry
const registry = createRegistry();
registry.register('enrich', () => enrichTransformation);
registry.register('normalize', () => normalizeTransformation);
registry.register('validate', () => validateTransformation);

// Runtime plugin example (simulating hot-reload)
registry.register('hash', () => ({
  name: 'hash',
  apply(msg: Message): Message {
    const payloadStr = JSON.stringify(msg.payload);
    const hash = btoa(payloadStr).slice(0, 8);
    return { ...msg, payload: { ...(msg.payload as object), hash } };
  }
}));

console.log('Available transformations:', registry.list());

// Single transformation pipeline
const pipeline = createPipeline(registry);

// Process messages with different transformation types
const msg1 = { payload: { data: 'HELLO WORLD' }, metadata: { transformationType: 'normalize' } };
const msg2 = { payload: { userId: 123 }, metadata: { transformationType: 'enrich' } };
const msg3 = { payload: { data: 'test' }, metadata: { transformationType: 'validate' } };
const msg4 = { payload: { data: 'unknown' }, metadata: { transformationType: 'hash' } };
const msg5 = { payload: { data: 'no type' }, metadata: {} }; // uses default

console.log('Normalize:', pipeline(msg1));
console.log('Enrich:', pipeline(msg2));
console.log('Validate:', pipeline(msg3));
console.log('Hash:', pipeline(msg4));
console.log('Default:', pipeline(msg5));

// Chained pipeline example
const enrichValidatePipeline = createChainedPipeline(registry, ['enrich', 'validate']);
const chainedResult = enrichValidatePipeline({ payload: { data: 'test' }, metadata: {} });
console.log('Chained:', chainedResult);

// Unregister example
registry.unregister('hash');
console.log('After unregister:', registry.list());
```

