## Code Example
```typescript
interface EvictionPolicy<K, V> {
  evict(cache: Map<K, V>, accessLog: Map<K, number>): K;
  touch(key: K): void;
}

class LRUPolicy<K, V> implements EvictionPolicy<K, V> {
  private accessOrder: Map<K, number> = new Map();
  private timestamp = 0;

  evict(cache: Map<K, V>, accessLog: Map<K, number>): K {
    let oldestKey: K | null = null;
    let oldestTime = Infinity;

    for (const [key] of cache) {
      const time = this.accessOrder.get(key) ?? 0;
      if (time < oldestTime) {
        oldestTime = time;
        oldestKey = key;
      }
    }

    return oldestKey!;
  }

  touch(key: K): void {
    this.accessOrder.set(key, ++this.timestamp);
  }
}

class LFUPolicy<K, V> implements EvictionPolicy<K, V> {
  private frequencies: Map<K, number> = new Map();

  evict(cache: Map<K, V>, accessLog: Map<K, number>): K {
    let leastUsedKey: K | null = null;
    let lowestFreq = Infinity;

    for (const [key] of cache) {
      const freq = this.frequencies.get(key) ?? 0;
      if (freq < lowestFreq) {
        lowestFreq = freq;
        leastUsedKey = key;
      }
    }

    return leastUsedKey!;
  }

  touch(key: K): void {
    const current = this.frequencies.get(key) ?? 0;
    this.frequencies.set(key, current + 1);
  }
}

class TTLPolicy<K, V> implements EvictionPolicy<K, V> {
  private timestamps: Map<K, number> = new Map();
  private readonly ttlMs: number;

  constructor(ttlMs: number) {
    this.ttlMs = ttlMs;
  }

  evict(cache: Map<K, V>, accessLog: Map<K, number>): K {
    const now = Date.now();

    for (const [key, timestamp] of this.timestamps) {
      if (now - timestamp > this.ttlMs) {
        return key;
      }
    }

    const [firstKey] = cache.keys();
    return firstKey;
  }

  touch(key: K): void {
    this.timestamps.set(key, Date.now());
  }
}

class PolicyRegistry<K, V> {
  private policies = new Map<string, () => EvictionPolicy<K, V>>();

  register(name: string, factory: () => EvictionPolicy<K, V>): void {
    this.policies.set(name, factory);
  }

  create(name: string): EvictionPolicy<K, V> {
    const factory = this.policies.get(name);
    if (!factory) {
      throw new Error(`Unknown eviction policy: ${name}`);
    }
    return factory();
  }
}

class InMemoryCache<K, V> {
  private cache = new Map<K, V>();
  private policy: EvictionPolicy<K, V>;
  private maxSize: number;

  constructor(policy: EvictionPolicy<K, V>, maxSize: number = 100) {
    this.policy = policy;
    this.maxSize = maxSize;
  }

  get(key: K): V | undefined {
    const value = this.cache.get(key);
    if (value !== undefined) {
      this.policy.touch(key);
    }
    return value;
  }

  set(key: K, value: V): void {
    if (!this.cache.has(key) && this.cache.size >= this.maxSize) {
      const evictKey = this.policy.evict(this.cache, new Map());
      this.cache.delete(evictKey);
    }

    this.cache.set(key, value);
    this.policy.touch(key);
  }
}

const registry = new PolicyRegistry<string, any>();
registry.register('lru', () => new LRUPolicy<string, any>());
registry.register('lfu', () => new LFUPolicy<string, any>());
registry.register('ttl', () => new TTLPolicy<string, any>(5000));

const cache = new InMemoryCache(registry.create('lru'), 10);
```

