type Context = { [k: string]: any };
type Next = () => Promise<void>;
type Middleware = (ctx: Context, next: Next) => Promise<void>;

class Registry {
  private store = new Map<string, Middleware[]>();
  register(name: string, mw: Middleware) {
    const arr = this.store.get(name) ?? [];
    arr.push(mw); this.store.set(name, arr);
  }
  get(name: string): Middleware[] | undefined {
    return this.store.get(name);
  }
}

function compose(list: Middleware[]): Middleware {
  return async (ctx, next) => {
    let i = -1;
    const dispatch = async (idx: number) => {
      if (idx < 0) return next();
      const mw = list[idx];
      if (!mw) return next();
      await mw(ctx, () => dispatch(idx + 1));
    };
    await dispatch(0);
  };
}
```

