## Pluggable Logging System Design

### Minimal Interfaces

```typescript
// Core abstraction that all sinks must implement
interface LogSink {
  readonly name: string;
  log(entry: LogEntry): void | Promise<void>;
}

interface LogEntry {
  level: LogLevel;
  message: string;
  timestamp: Date;
  context?: Record<string, unknown>;
}

enum LogLevel {
  DEBUG = 0,
  INFO = 1,
  WARN = 2,
  ERROR = 3,
}
```

### Registry Structure

```typescript
class SinkRegistry {
  private sinks = new Map<string, LogSink>();

  register(sink: LogSink): void {
    if (this.sinks.has(sink.name)) {
      throw new Error(`Sink '${sink.name}' already registered`);
    }
    this.sinks.set(sink.name, sink);
  }

  unregister(name: string): boolean {
    return this.sinks.delete(name);
  }

  get(name: string): LogSink | undefined {
    return this.sinks.get(name);
  }

  getAll(): LogSink[] {
    return Array.from(this.sinks.values());
  }
}

// Core logger remains untouched when adding sinks
class Logger {
  constructor(private registry: SinkRegistry) {}

  log(entry: LogEntry): void {
    const sinks = this.registry.getAll();
    const asyncSinks = sinks.filter(s => this.isAsync(s));
    const syncSinks = sinks.filter(s => !this.isAsync(s));

    syncSinks.forEach(s => s.log(entry));
    asyncSinks.forEach(s => s.log(entry));
  }

  private isAsync(sink: LogSink): boolean {
    return (sink.log as (...args: unknown[]) => Promise<void>).length === 0;
  }
}
```

### Example Sinks

```typescript
// Synchronous console sink
class ConsoleSink implements LogSink {
  readonly name = 'console';

  log(entry: LogEntry): void {
    console.log(`[${entry.timestamp}] ${LogLevel[entry.level]}: ${entry.message}`);
  }
}

// Asynchronous file sink
class FileSink implements LogSink {
  readonly name = 'file';
  private stream: WriteStream;

  constructor(path: string) {
    this.stream = createWriteStream(path, { flags: 'a' });
  }

  async log(entry: LogEntry): Promise<void> {
    return new Promise((resolve, reject) => {
      this.stream.write(JSON.stringify(entry) + '\n', (err) => {
        err ? reject(err) : resolve();
      });
    });
  }
}

// Asynchronous remote sink
class RemoteSink implements LogSink {
  readonly name = 'remote';

  async log(entry: LogEntry): Promise<void> {
    await fetch('https://logs.example.com/api', {
      method: 'POST',
      body: JSON.stringify(entry),
    });
  }
}
```

### Per-Environment Configuration

```typescript
function createLogger(env: string): Logger {
  const registry = new SinkRegistry();

  // Always log to console
  registry.register(new ConsoleSink());

  if (env === 'production') {
    registry.register(new FileSink('/var/log/app.log'));
    registry.register(new RemoteSink());
  } else if (env === 'development') {
    registry.register(new FileSink('./logs/dev.log'));
  }

  return new Logger(registry);
}

const logger = createLogger(process.env.NODE_ENV || 'development');
```

### Sync vs Async Trade-offs

| Aspect | Synchronous | Asynchronous |
|--------|-------------|--------------|
| **Performance** | Blocks execution | Non-blocking |
| **Reliability** | May lose logs on crash | Buffers, retries |
| **Complexity** | Simple | Requires error handling |
| **Use Case** | Debug/dev | Production/high-volume |

**Recommendation**: Use synchronous sinks for development and debugging; use asynchronous sinks for production where throughput matters and some log loss is acceptable (or implement retry logic).

Use a Channel interface with a Registry to plug in new channels at runtime. The dispatcher checks user preferences, attempts delivery through channels in order of priority, and rolls back to a fallback if all channels fail. Minimal interfaces: Channel, ChannelFactory, and ChannelRegistry.

```typescript
interface Channel {
  readonly name: string;
  deliver(recipient: string, message: Message): Promise<DeliveryResult>;
}

interface ChannelFactory {
  create(): Channel;
}

interface ChannelRegistry {
  register(name: string, factory: ChannelFactory): void;
  get(name: string): ChannelFactory | undefined;
  list(): string[];
}

interface Message {
  subject?: string;
  body: string;
}

interface DeliveryResult {
  success: boolean;
  error?: string;
}

class NotificationDispatcher {
  constructor(
    private registry: ChannelRegistry,
    private preferences: Map<string, string[]>,
    private fallbackChannel: string = 'email'
  ) {}

  async notify(userId: string, message: Message): Promise<DeliveryResult> {
    const channels = this.preferences.get(userId) || [this.fallbackChannel];
    const errors: string[] = [];

    for (const channelName of channels) {
      const factory = this.registry.get(channelName);
      if (!factory) continue;

      const result = await factory.create().deliver(userId, message);
      if (result.success) return result;
      errors.push(`${channelName}: ${result.error}`);
    }

    return { success: false, error: `All channels failed: ${errors.join('; ')}` };
  }
}

// Example usage
const registry = new InMemoryChannelRegistry();
registry.register('email', () => new EmailChannel());
registry.register('push', () => new PushChannel());

const dispatcher = new NotificationDispatcher(registry, userPrefs);
await dispatcher.notify('user123', { subject: 'Alert', body: 'Hello!' });
```

