## Code Example

```typescript
interface CommandHandler<T> {
  execute(payload: T): Promise<void>;
}

type Registry<T> = Map<string, CommandHandler<T>>;

interface RetryPolicy {
  maxRetries: number;
  backoffMs: number;
}

class Dispatcher<T> {
  private registry: Registry<T> = new Map();
  private policies: Map<string, RetryPolicy> = new Map();
  // pseudo semaphore for rate limiting
  async dispatch(name: string, payload: T): Promise<void> {
    const handler = this.registry.get(name);
    if (!handler) throw new Error('Handler not found');
    const policy = this.policies.get(name) ?? { maxRetries: 0, backoffMs: 0 };
    let attempt = 0;
    while (true) {
      try {
        await handler.execute(payload);
        return;
      } catch (e) {
        if (attempt >= policy.maxRetries) throw e;
        await new Promise(r => setTimeout(r, policy.backoffMs));
        attempt++;
      }
    }
  }
}
```

