## Code Example
```typescript
interface Backend {
  name: string;
  log(level: LogLevel, msg: string, meta?: Record<string, unknown>): void | Promise<void>;
}

type LogLevel = 'debug' | 'info' | 'warn' | 'error';

class BackendRegistry {
  private backends = new Map<string, Backend>();

  register(name: string, backend: Backend): void {
    this.backends.set(name, backend);
  }

  get(name: string): Backend | undefined {
    return this.backends.get(name);
  }

  unregister(name: string): boolean {
    return this.backends.delete(name);
  }
}

class Logger {
  constructor(private registry: BackendRegistry) {}

  async log(level: LogLevel, msg: string, meta?: Record<string, unknown>): Promise<void> {
    const backends = Array.from(this.registry['backends'].values());
    await Promise.allSettled(
      backends.map(backend =>
        Promise.resolve(backend.log(level, msg, meta)).catch(() => {})
      )
    );
  }

  debug(msg: string, meta?: Record<string, unknown>): Promise<void> {
    return this.log('debug', msg, meta);
  }

  info(msg: string, meta?: Record<string, unknown>): Promise<void> {
    return this.log('info', msg, meta);
  }

  warn(msg: string, meta?: Record<string, unknown>): Promise<void> {
    return this.log('warn', msg, meta);
  }

  error(msg: string, meta?: Record<string, unknown>): Promise<void> {
    return this.log('error', msg, meta);
  }
}

// Usage Example
const registry = new BackendRegistry();

const consoleBackend: Backend = {
  name: 'console',
  log(level, msg, meta) {
    console.log(`[${level}] ${msg}`, meta || '');
  },
};

const fileBackend: Backend = {
  name: 'file',
  async log(level, msg, meta) {
    // Write to file implementation
  },
};

registry.register('console', consoleBackend);
registry.register('file', fileBackend);

const logger = new Logger(registry);
logger.info('Application started', { version: '1.0.0' });
```

