questions.answer:
Create a Command interface and a CommandRegistry class to manage CLI commands at runtime.

**Command interface:**
```typescript
interface Command {
  readonly name: string;
  readonly description?: string;
  execute(args: readonly string[]): void;
}
```

**CommandRegistry class:**
```typescript
type CommandHandler = (args: readonly string[]) => void;

class CommandRegistry {
  private commands = new Map<string, Command>();

  register(cmd: Command): void {
    if (this.commands.has(cmd.name)) {
      throw new Error(`Command '${cmd.name}' is already registered`);
    }
    this.commands.set(cmd.name, cmd);
  }

  get(name: string): Command | undefined {
    return this.commands.get(name);
  }

  dispatch(name: string, args: readonly string[] = []): void {
    const command = this.commands.get(name);
    if (!command) {
      throw new Error(`Unknown command: ${name}`);
    }
    command.execute(args);
  }

  list(): readonly string[] {
    return Array.from(this.commands.keys());
  }
}
```

**Usage example:**
```typescript
const registry = new CommandRegistry();

// Register commands at runtime
registry.register({
  name: 'greet',
  description: 'Greet the user',
  execute: (args) => console.log(`Hello, ${args[0] || 'World'}!`)
});

registry.register({
  name: 'add',
  description: 'Add two numbers',
  execute: (args) => {
    const sum = args.map(Number).reduce((a, b) => a + b, 0);
    console.log(`Result: ${sum}`);
  }
});

// Simulate CLI parsing and dispatch
function handleInput(input: string): void {
  const [cmdName, ...cmdArgs] = input.trim().split(' ');
  if (!cmdName) {
    console.log('Available commands:', registry.list().join(', '));
    return;
  }
  try {
    registry.dispatch(cmdName, cmdArgs);
  } catch (err) {
    console.error(err instanceof Error ? err.message : err);
  }
}

// Test it
handleInput('greet Alice');      // Output: Hello, Alice!
handleInput('add 5 10 20');       // Output: Result: 35
handleInput('unknown');          // Output: Error: Unknown command: unknown
```

