## Code Example

```typescript
interface IdempotencyStrategy {
  shouldRetry(request: Request, response: Response, attempt: number): boolean;
  backoff(attempt: number): number;
}

type StrategyFactory = () => IdempotencyStrategy;

class IdempotencyRegistry {
  private strategies = new Map<string, StrategyFactory>();
  private defaultStrategy: IdempotencyStrategy;

  register(name: string, factory: StrategyFactory): void {
    this.strategies.set(name, factory);
  }

  resolve(name?: string): IdempotencyStrategy {
    if (name && this.strategies.has(name)) {
      return this.strategies.get(name)!();
    }
    return this.defaultStrategy;
  }
}
```

## Why This Is Asked

Tests ability to design an extensible plugin mechanism using simple interfaces and a runtime registry.

