## Code Example

```ts
interface Command {
  id: string
  name: string
  prerequisites?: string[]
  execute(ctx: any): void
}

class Registry {
  private map = new Map<string, {cmd: Command, priority: number, ts: number}>();
  register(cmd: Command, priority = 0){
    this.map.set(cmd.name, {cmd, priority, ts: Date.now()});
  }
  dispatch(name: string, ctx: any){
    const entry = this.map.get(name);
    if(!entry) return;
    if((entry.cmd.prerequisites ?? []).some(p => !ctx.flags?.includes(p))) return;
    entry.cmd.execute(ctx);
  }
  unregister(name: string){ this.map.delete(name); }
  clear(){ this.map.clear(); }
}
``` 

