interface TelemetrySink {
  send(event: TelemetryEvent): Promise<void>;
  flush?(): Promise<void>;
  shutdown?(): Promise<void>;
}

class PluginRegistry {
  #sinks = new Map();

  register(name, factory) {
    this.#sinks.set(name, factory(this));
  }

  get(name) {
    return this.#sinks.get(name);
  }

  list() {
    return Array.from(this.#sinks.keys());
  }
}

class SyslogSink {
  #buffer = [];
  #batchSize = 100;
  #flushInterval = 5000;
  #paused = false;
  #controller = new AbortController();

  constructor(options = {}) {
    this.#batchSize = options.batchSize ?? 100;
    this.#flushInterval = options.flushInterval ?? 5000;
    this.#startFlushTimer();
  }

  async send(event) {
    if (this.#paused) {
      throw new Error('Backpressure: sink is paused');
    }

    this.#buffer.push(event);

    if (this.#buffer.length >= this.#batchSize) {
      await this.flush();
    }

    if (this.#buffer.length > this.#batchSize * 0.8) {
      this.#paused = true;
    }
  }

  async flush() {
    if (this.#buffer.length === 0) return;

    const batch = this.#buffer.splice(0, this.#batchSize);
    try {
      await this.#sendToSyslog(batch);
      this.#paused = false;
    } catch (err) {
      this.#buffer.unshift(...batch);
      throw err;
    }
  }

  async shutdown() {
    this.#controller.abort();
    await this.flush();
  }

  #startFlushTimer() {
    setInterval(() => this.flush(), this.#flushInterval);
  }

  async #sendToSyslog(batch) {
    // Send batch to syslog endpoint
  }
}

// Usage
const registry = new PluginRegistry();
registry.register('syslog', () => new SyslogSink({ batchSize: 50 }));
```

