## Code Example

```typescript
interface FlagContext {
  userId?: string;
  device?: string;
  region?: string;
  attributes?: Record<string, unknown>;
}

interface RolloutStrategy {
  name: string;
  evaluate(context: FlagContext, config: RolloutConfig): boolean;
}

interface RolloutConfig {
  percentage?: number;
  segment?: string;
  shardKey?: string;
}

class StrategyRegistry {
  private strategies = new Map<string, () => RolloutStrategy>();

  register(name: string, factory: () => RolloutStrategy): void {
    this.strategies.set(name, factory);
  }

  get(name: string): RolloutStrategy {
    const factory = this.strategies.get(name);
    if (!factory) throw new Error(`Strategy '${name}' not found`);
    return factory();
  }
}

class FeatureFlagEngine {
  private registry: StrategyRegistry;
  private strategyCache = new Map<string, RolloutStrategy>();

  constructor(registry: StrategyRegistry) {
    this.registry = registry;
  }

  evaluate(flag: string, context: FlagContext, config: RolloutConfig): boolean {
    const strategy = this.getStrategy(config.strategy);
    return strategy.evaluate(context, config);
  }

  private getStrategy(name: string): RolloutStrategy {
    if (!this.strategyCache.has(name)) {
      this.strategyCache.set(name, this.registry.get(name));
    }
    return this.strategyCache.get(name)!;
  }
}
```

