```typescript
interface BackoffStrategy {
  nextDelay(attempt: number, error?: unknown): number;
  reset(): void;
}

type BackoffFactory = (options?: Record<string, unknown>) => BackoffStrategy;

interface PolicyRegistry {
  register(name: string, factory: BackoffFactory): void;
  get(name: string): BackoffFactory;
  has(name: string): boolean;
  unregister(name: string): boolean;
}

class PolicyRegistryImpl implements PolicyRegistry {
  private factories = new Map<string, BackoffFactory>();
  private readonly builtIns = ['exponential', 'fixed', 'jitter'] as const;

  register(name: string, factory: BackoffFactory): void {
    if (this.factories.has(name)) {
      throw new Error(`Policy '${name}' is already registered`);
    }
    this.factories.set(name, factory);
  }

  get(name: string): BackoffFactory {
    const factory = this.factories.get(name);
    if (!factory) {
      throw new Error(`Unknown backoff policy: '${name}'. Available: ${this.list()}`);
    }
    return factory;
  }

  has(name: string): boolean {
    return this.factories.has(name);
  }

  unregister(name: string): boolean {
    if (this.builtIns.includes(name as 'exponential' | 'fixed' | 'jitter')) {
      throw new Error(`Cannot unregister built-in policy: '${name}'`);
    }
    return this.factories.delete(name);
  }

  list(): string[] {
    return [...this.factories.keys()];
  }
}

class ExponentialBackoff implements BackoffStrategy {
  private readonly maxAttempts: number;
  private readonly base: number;
  private readonly cap: number;

  constructor(base = 100, cap = 30000, maxAttempts = 10) {
    this.base = base;
    this.cap = cap;
    this.maxAttempts = maxAttempts;
  }

  nextDelay(attempt: number): number {
    if (attempt >= this.maxAttempts) return -1;
    return Math.min(this.cap, this.base * Math.pow(2, attempt));
  }

  reset(): void {}
}

class FixedBackoff implements BackoffStrategy {
  constructor(private readonly delay = 1000) {}

  nextDelay(): number {
    return this.delay;
  }

  reset(): void {}
}

class JitterBackoff implements BackoffStrategy {
  constructor(
    private readonly base = 100,
    private readonly cap = 30000,
    private readonly jitterFn = () => Math.random()
  ) {}

  nextDelay(attempt: number): number {
    const exponential = Math.min(this.cap, this.base * Math.pow(2, attempt));
    const jittered = exponential * (0.5 + this.jitterFn() * 0.5);
    return Math.floor(jittered);
  }

  reset(): void {}
}

function createExponentialFactory(opts?: Record<string, unknown>): BackoffStrategy {
  return new ExponentialBackoff(
    opts?.base as number ?? 100,
    opts?.cap as number ?? 30000,
    opts?.maxAttempts as number ?? Infinity
  );
}

function createFixedFactory(opts?: Record<string, unknown>): BackoffStrategy {
  return new FixedBackoff(opts?.delay as number ?? 1000);
}

function createJitterFactory(opts?: Record<string, unknown>): BackoffStrategy {
  return new JitterBackoff(
    opts?.base as number ?? 100,
    opts?.cap as number ?? 30000
  );
}

const globalRegistry = new PolicyRegistryImpl();

globalRegistry.register('exponential', createExponentialFactory);
globalRegistry.register('fixed', createFixedFactory);
globalRegistry.register('jitter', createJitterFactory);

export { BackoffStrategy, BackoffFactory, PolicyRegistry, globalRegistry };

// === Usage Example ===
interface RetryableTask {
  name: string;
  backoffPolicy: string;
  backoffOptions?: Record<string, unknown>;
}

async function executeWithRetry(
  task: RetryableTask,
  fn: () => Promise<void>,
  registry: PolicyRegistry = globalRegistry
): Promise<void> {
  const factory = registry.get(task.backoffPolicy);
  const strategy = factory(task.backoffOptions);
  let attempt = 0;

  while (true) {
    try {
      await fn();
      return;
    } catch (error) {
      const delay = strategy.nextDelay(attempt++, error);
      if (delay < 0) throw error;
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }
}

// Custom policy registration at runtime
globalRegistry.register('linear', (opts) => {
  const increment = (opts?.increment as number) ?? 1000;
  return {
    nextDelay: (attempt: number) => attempt * increment,
    reset: () => {}
  };
});

// Usage
const task: RetryableTask = {
  name: 'send-notification',
  backoffPolicy: 'exponential',
  backoffOptions: { base: 200, cap: 10000, maxAttempts: 5 }
};

executeWithRetry(task, async () => {
  console.log('Executing task...');
  throw new Error('Transient failure');
});
```

