## Why This Is Asked
This question assesses the ability to design extensible CLI architectures with runtime plugin support and graceful user experience.

### Key Concepts
- **Command pattern**: Encapsulates operations as first-class objects
- **Registry**: Enables dynamic command registration and lookup
- **Alias support**: Handles naming conflicts and provides convenient shortcuts
- **Auto-generated help**: Constructed from command metadata
- **Graceful failure**: Provides helpful error messages for unrecognized commands

### Code Example
```typescript
interface CommandContext {
  args: Record<string, unknown>;
  stdin: NodeJS.ReadableStream;
  stdout: NodeJS.WritableStream;
  stderr: NodeJS.WritableStream;
}

interface CommandDefinition {
  name: string;
  aliases: string[];
  description: string;
  parse(args: string[]): Record<string, unknown>;
  execute(ctx: CommandContext): Promise<void> | void;
}

class CommandRegistry {
  private commands = new Map<string, CommandDefinition>();

  register(cmd: CommandDefinition): void {
    this.commands.set(cmd.name, cmd);
    cmd.aliases.forEach(alias => this.commands.set(alias, cmd));
  }

  resolve(name: string): CommandDefinition | undefined {
    return this.commands.get(name);
  }

  getCommands(): CommandDefinition[] {
    return [...new Set(this.commands.values())];
  }

  generateHelp(): string {
    const commands = this.getCommands();
    const longestName = Math.max(...commands.map(c => c.name.length));
    return [
      'Usage: cli <command> [options]',
      '',
      'Commands:',
      ...commands.map(c => `  ${c.name.padEnd(longestName)}  ${c.description}`),
    ].join('\n');
  }
}

async function main(argv: string[]) {
  const [cmdName, ...args] = argv.slice(2);
  const registry = new CommandRegistry();

  // Register commands
  registry.register({
    name: 'greet',
    aliases: ['g'],
    description: 'Greet a user',
    parse(args) {
      const name = args[0] || 'World';
      return { name };
    },
    execute({ args, stdout }) {
      stdout.write(`Hello, ${args.name}!\n`);
    },
  });

  if (!cmdName) {
    console.log(registry.generateHelp());
    process.exit(0);
  }

  const cmd = registry.resolve(cmdName);
  if (!cmd) {
    console.error(`Error: Unknown command '${cmdName}'`);
    console.error(registry.generateHelp());
    process.exit(1);
  }

  const parsedArgs = cmd.parse(args);
  cmd.execute({
    args: parsedArgs,
    stdin: process.stdin,
    stdout: process.stdout,
    stderr: process.stderr,
  });
}

main(process.argv);
```

