Design a registry-driven pipeline where inbound requests flow through registered transformers in order (e.g., path rewrite → header augmentation). Each transformer exposes a `transform(req)` method and an optional `order` property to control execution sequence.

```typescript
interface Request {
  path: string;
  headers: Record<string, string>;
  body?: unknown;
}

interface Transformer {
  name: string;
  order?: number;
  transform(req: Request): Request;
}

class TransformerRegistry {
  private transformers: Transformer[] = [];

  register(transformer: Transformer): void {
    this.transformers.push(transformer);
    this.transformers.sort((a, b) => (a.order ?? 100) - (b.order ?? 100));
  }

  process(req: Request): Request {
    return this.transformers.reduce((req, t) => t.transform(req), req);
  }
}

// Usage
const registry = new TransformerRegistry();
registry.register({ name: 'pathRewrite', order: 1, transform: (req) => ({ ...req, path: req.path.replace('/v1', '') }) });
registry.register({ name: 'headerAug', order: 2, transform: (req) => ({ ...req, headers: { ...req.headers, 'x-gateway': 'true' } }) });

const result = registry.process({ path: '/v1/users', headers: {} });
```

