## Code Example
```typescript
interface RateLimiterStrategy {
  tryAcquire(tokens: number): boolean;
}
type RateLimiterFactory = () => RateLimiterStrategy;

class RuntimeRegistry {
  private factories = new Map<string, RateLimiterFactory>();
  private snapshot: Map<string, RateLimiterFactory> = new Map();

  register(name: string, f: RateLimiterFactory) {
    this.factories.set(name, f);
    // atomically swap snapshot for readers
    this.snapshot = new Map(this.factories);
  }

  getStrategyFor(name: string): RateLimiterStrategy {
