Use a registry keyed by format type that returns a Serializer instance. Define the Serializer interface with serialize and deserialize methods, then implement JsonSerializer, AvroSerializer, and ParquetSerializer. The SerializerRegistry stores implementations by format key and provides a get method to retrieve the appropriate serializer based on runtime metadata.

```typescript
interface Serializer<T = unknown> {
  serialize(obj: T): string | Buffer;
  deserialize(data: string | Buffer): T;
}

class JsonSerializer implements Serializer {
  serialize(obj: unknown): string {
    return JSON.stringify(obj);
  }

  deserialize(data: string): unknown {
    return JSON.parse(data);
  }
}

class AvroSerializer implements Serializer {
  serialize(obj: unknown): Buffer {
    // Avro binary encoding
    return Buffer.alloc(0);
  }

  deserialize(data: Buffer): unknown {
    // Avro decoding
    return {};
  }
}

class ParquetSerializer implements Serializer {
  serialize(obj: unknown): Buffer {
    // Parquet encoding
    return Buffer.alloc(0);
  }

  deserialize(data: Buffer): unknown {
    // Parquet decoding
    return {};
  }
}

class SerializerRegistry {
  private serializers = new Map<string, Serializer>();

  register(format: string, serializer: Serializer): void {
    this.serializers.set(format, serializer);
  }

  get(format: string): Serializer {
    const serializer = this.serializers.get(format);
    if (!serializer) {
      throw new Error(`Unknown format: ${format}`);
    }
    return serializer;
  }
}

// Usage
const registry = new SerializerRegistry();
registry.register('json', new JsonSerializer());
registry.register('avro', new AvroSerializer());
registry.register('parquet', new ParquetSerializer());

function processDataset(
  data: unknown,
  metadata: { format: string },
  registry: SerializerRegistry
): string | Buffer {
  const serializer = registry.get(metadata.format);
  return serializer.serialize(data);
}
```

New formats can be added by implementing the Serializer interface and registering them—no modifications to the processing logic required.

