interface RuleProvider {
  name: string;
  evaluate(ctx: any): boolean | Promise<boolean>;
}
type Operator = 'AND' | 'OR';
interface PolicyNode {
  op?: Operator;
  rule?: RuleProvider;
  children?: PolicyNode[];
}
class Registry {
  private map = new Map<string, RuleProvider>();
  register(r: RuleProvider) { this.map.set(r.name, r); }
  get(name: string) { return this.map.get(name); }
}
class PolicyEngine {
  constructor(private registry: Registry, private root: PolicyNode) {}
  async evaluate(ctx: any): Promise<boolean> {
    // simplified traversal example
    const walk = async (node?: PolicyNode): Promise<boolean> => {
      if (!node) return true;
      if (node.rule) return await node.rule.evaluate(ctx);
      if (node.children && node.children.length) {
        let acc = node.children[0].op === 'AND' ? true : false;
        for (const c of node.children) {
          const val = await walk(c);
          acc = (node.op === 'OR') ? acc || val : acc && val;
        }
        return acc;
      }
      return true;
    };
    return await walk(this.root);
  }
}
```

