Use a decorator-style pipeline pattern: Define a Service interface with an execute(req) method that returns a Promise. The CoreService implements the core business logic. Each Wrapper wraps a Service and accepts a next Service in its constructor, returning a new Service with added functionality. A WrapperRegistry maintains a map of wrapper names to wrapper factories, enabling runtime registration. For each client, compose wrappers in the desired order by chaining them—each wrapper receives the next service in the chain and returns an enhanced service.

```typescript
interface Service<Request, Response> {
  execute(req: Request): Promise<Response>;
}

class CoreService implements Service<any, any> {
  async execute(req: any): Promise<any> {
    // core business logic
  }
}

type WrapperFactory = (next: Service<any, any>) => Service<any, any>;

class WrapperRegistry {
  private wrappers = new Map<string, WrapperFactory>();

  register(name: string, factory: WrapperFactory): void {
    this.wrappers.set(name, factory);
  }

  createPipeline(wrapperNames: string[], core: Service<any, any>): Service<any, any> {
    let service = core;
    for (const name of wrapperNames.reverse()) {
      const factory = this.wrappers.get(name);
      if (!factory) throw new Error(`Wrapper '${name}' not found`);
      service = factory(service);
    }
    return service;
  }
}

// Example wrappers
const CachingWrapper: WrapperFactory = (next) => ({
  async execute(req: any) {
    const cacheKey = JSON.stringify(req);
    const cached = cache.get(cacheKey);
    if (cached) return cached;
    const result = await next.execute(req);
    cache.set(cacheKey, result);
    return result;
  }
});

const AuthorizationWrapper: WrapperFactory = (next) => ({
  async execute(req: any) {
    if (!req.user?.hasPermission) {
      throw new Error('Unauthorized');
    }
    return next.execute(req);
  }
});

// Usage
const registry = new WrapperRegistry();
registry.register('cache', CachingWrapper);
registry.register('auth', AuthorizationWrapper);

const core = new CoreService();
const clientPipeline = registry.createPipeline(['auth', 'cache'], core);
```

