- **Deterministic ordering** via explicit step dependencies and metadata

## Code Example
```typescript
interface Context {
  env: Record<string, string>;
  artifacts: Record<string, unknown>;
}

interface ExecutionResult {
  success: boolean;
  output?: unknown;
  error?: Error;
  duration: number;
}

interface RetryPolicy {
  maxAttempts: number;
  backoffMs: number;
  exponential?: boolean;
}

interface Job {
  execute(context: Context): Promise<ExecutionResult>;
}

class Registry {
  private jobs = new Map<string, new () => Job>>();

  register(name: string, jobClass: new () => Job): void {
    this.jobs.set(name, jobClass);
  }

  resolve(name: string): Job {
    const JobClass = this.jobs.get(name);
    if (!JobClass) throw new Error(`Job '${name}' not found in registry`);
    return new JobClass();
  }

  has(name: string): boolean {
    return this.jobs.has(name);
  }
}

type StepConfig = {
  name: string;
  retry?: RetryPolicy;
  parallel?: boolean;
  dependsOn?: string[];
};

class Orchestrator {
  constructor(private registry: Registry) {}

  async run(
    pipeline: { steps: StepConfig[] },
    initialContext: Context
  ): Promise<ExecutionResult[]> {
    const results = new Map<string, ExecutionResult>();
    const stepMap = new Map(pipeline.steps.map(s => [s.name, s]));
    const completed = new Set<string>();

    while (completed.size < pipeline.steps.length) {
      const readyStep = pipeline.steps.find(step => {
        if (completed.has(step.name)) return false;
        const deps = step.dependsOn || [];
        return deps.every(d => completed.has(d));
      });

      if (!readyStep) throw new Error('Circular dependency detected');

      const result = await this.executeStep(readyStep, {
        ...initialContext,
        artifacts: { ...initialContext.artifacts },
      });

      results.set(readyStep.name, result);
      completed.add(readyStep.name);

      if (!result.success) {
        throw new Error(`Step '${readyStep.name}' failed: ${result.error?.message}`);
      }
    }

    return Array.from(results.values());
  }

  private async executeStep(
    step: StepConfig,
    context: Context
  ): Promise<ExecutionResult> {
    const job = this.registry.resolve(step.name);
    const policy = step.retry ?? { maxAttempts: 1, backoffMs: 1000 };
    let lastError: Error | undefined;

    for (let attempt = 1; attempt <= policy.maxAttempts; attempt++) {
      const start = Date.now();
      try {
        const result = await job.execute(context);
        result.duration = Date.now() - start;
        if (result.success) return result;
        lastError = result.error;
      } catch (e) {
        lastError = e as Error;
      }

      if (attempt < policy.maxAttempts) {
        const delay = policy.exponential
          ? policy.backoffMs * Math.pow(2, attempt - 1)
          : policy.backoffMs;
        await new Promise(r => setTimeout(r, delay));
      }
    }

    return { success: false, error: lastError, duration: 0 };
  }
}

// Usage
const registry = new Registry();
registry.register('build', BuildJob);
registry.register('test', TestJob);
registry.register('deploy', DeployJob);

const orchestrator = new Orchestrator(registry);
const results = await orchestrator.run(
  {
    steps: [
      { name: 'build', retry: { maxAttempts: 3, backoffMs: 1000, exponential: true } },
      { name: 'test', dependsOn: ['build'], parallel: false },
      { name: 'deploy', dependsOn: ['test'], retry: { maxAttempts: 2, backoffMs: 2000 } },
    ],
  },
  { env: { CI: 'true' }, artifacts: {} }
);
```

