type Context = { routeKey: string; req: any; res: any; data?: any };
interface Processor { handle(ctx: Context, next: () => Promise<void>): Promise<void>; }
interface RouteConfig { path: string; method: string; pre: Processor[]; handlers: Processor[]; post: Processor[]; }
