## Why This Is Asked

This question evaluates the ability to design a runtime-extensible, order-sensitive weaving system with per-module isolation, robust failure handling, and a practical TypeScript usage pattern.

## Key Concepts

- Dynamic proxy wrapping around a service
- Runtime registry for concerns by name
- Ordered execution with per-module scoping
- Safe error isolation and fault tolerance
- Trade-offs: dependency injection's explicit wiring versus AOP's seamless weaving

## Code Example

```typescript
interface IConcern {
  name: string;
  before(ctx: ConcernContext): void | Promise<void>;
  after?(ctx: ConcernContext, result: unknown): void | Promise<void>;
  around?(ctx: ConcernContext, next: () => Promise<unknown>): Promise<unknown>;
}

interface ConcernContext {
  method: string;
  args: unknown[];
  module: string;
  [key: string]: unknown;
}

class ConcernRegistry {
  private concerns = new Map<string, Map<string, IConcern>>();

  register(module: string, concern: IConcern): void {
    if (!this.concerns.has(module)) {
      this.concerns.set(module, new Map());
    }
    this.concerns.get(module)!.set(concern.name, concern);
  }

  toggle(module: string, name: string, enabled: boolean): void {
    const moduleConcerns = this.concerns.get(module);
    if (moduleConcerns?.has(name)) {
      moduleConcerns.get(name)!["enabled"] = enabled;
    }
  }

  getOrdered(module: string, order: string[]): IConcern[] {
    const moduleConcerns = this.concerns.get(module) || new Map();
    return order
      .map(name => moduleConcerns.get(name))
      .filter((c): c is IConcern => c !== undefined && (c as any)["enabled"] !== false);
  }
}

function wrap<T>(target: T, module: string, registry: ConcernRegistry, order: string[]): T {
  return new Proxy(target, {
    async get(_target, prop) {
      const member = (target as any)[prop];
      if (typeof member !== "function") return member;

      return async (...args: unknown[]) => {
        const ctx: ConcernContext = { method: prop as string, args, module };
        const concerns = registry.getOrdered(module, order);

        const pipeline = concerns.reduce(
          (next, concern) => async () => {
            try {
              await concern.before?.(ctx);
              const result = await next();
              await concern.after?.(ctx, result);
              return result;
            } catch (e) {
              console.error(`Concern ${concern.name} failed:`, e);
              return next();
            }
          },
          () => member.apply(target, args)
        );

        return pipeline();
      };
    },
  }) as T;
}

// Usage
const loggingConcern: IConcern = {
  name: "logging",
  before: (ctx) => console.log(`Calling ${ctx.method}`),
  after: (ctx, result) => console.log(`Finished ${ctx.method}`),
};

const metricsConcern: IConcern = {
  name: "metrics",
  before: (ctx) => { (ctx as any).start = Date.now(); },
  after: (ctx) => { console.log(`Duration: ${Date.now() - (ctx as any).start}ms`); },
};

const registry = new ConcernRegistry();
registry.register("users", loggingConcern);
registry.register("users", metricsConcern);

const service = { getUser: (id: number) => `User ${id}` };
const wrapped = wrap(service, "users", registry, ["logging", "metrics"]);

wrapped.getUser(1); // Logs: Calling getUser, Duration: ..., Finished getUser
```

## Why This Is Asked
This question assesses a candidate's ability to design dynamic, extensible systems that support runtime behavior modification without redeployment. It tests understanding of the Strategy pattern combined with registry-based dependency injection, while also probing knowledge of per-client state isolation and safe hot-swapping mechanisms in concurrent environments.

## Key Concepts
