- Per-client state isolation using atomic references or copy-on-write semantics
- Thread-safety considerations in highly concurrent environments
- Implementation variants: TokenBucket, LeakyBucket, and SlidingWindow algorithms

## Code Example
```typescript
interface IRateLimiterStrategy {
  tryAcquire(n: number): Promise<boolean>;
}

class RateLimiterRegistry {
  private strategies = new Map<string, () => IRateLimiterStrategy>();
  private clients = new Map<string, { strategy: IRateLimiterStrategy; version: number }>();
  private rwLock = { read: 0, write: 0 };

  register(name: string, factory: () => IRateLimiterStrategy): void {
    this.strategies.set(name, factory);
  }

  setClientStrategy(clientId: string, name: string): void {
    const factory = this.strategies.get(name);
    if (!factory) throw new Error(`Strategy '${name}' not found`);
    this.clients.set(clientId, { strategy: factory(), version: Date.now() });
  }

  async handleRequest(clientId: string, amount: number): Promise<boolean> {
    const client = this.clients.get(clientId);
    if (!client) return true;
    return client.strategy.tryAcquire(amount);
  }
}
```

