# Runtime-Configurable Cache Eviction Engine

Use the **Strategy Pattern** with a **Registry** for runtime-pluggable eviction policies.

## Interfaces

```typescript
interface CacheEntry<V> {
  value: V;
  accessTime: number;
  accessCount: number;
}

interface EvictionStrategy<K, V> {
  onAccess(key: K, entry: CacheEntry<V>): void;
  evictIfNeeded(cache: Cache<K, V>): K | null;
  reset(): void;
}

interface PolicyRegistry<K, V> {
  register(name: string, factory: () => EvictionStrategy<K, V>): void;
  deregister(name: string): boolean;
  has(name: string): boolean;
}
```

## Eviction Policy Implementations

```typescript
class LRUStrategy<K, V> implements EvictionStrategy<K, V> {
  private accessOrder: K[] = [];

  onAccess(key: K): void {
    const idx = this.accessOrder.indexOf(key);
    if (idx > -1) this.accessOrder.splice(idx, 1);
    this.accessOrder.push(key);
  }

  evictIfNeeded(cache: Cache<K, V>): K | null {
    if (cache.size() < cache.getCapacity()) return null;
    const oldest = this.accessOrder.shift();
    if (oldest) cache.delete(oldest);
    return oldest;
  }

  reset(): void {
    this.accessOrder = [];
  }
}

class LFUStrategy<K, V> implements EvictionStrategy<K, V> {
  private freqMap = new Map<K, number>();
  private minFreq = 1;

  onAccess(key: K): void {
    const count = (this.freqMap.get(key) || 0) + 1;
    this.freqMap.set(key, count);
    if (count < this.minFreq) this.minFreq = count;
  }

  evictIfNeeded(cache: Cache<K, V>): K | null {
    if (cache.size() < cache.getCapacity()) return null;

    let evictKey: K | null = null;
    for (const [key, freq] of this.freqMap) {
      if (freq === this.minFreq) {
        evictKey = key;
        break;
      }
    }

    if (evictKey) {
      this.freqMap.delete(evictKey);
      cache.delete(evictKey);

      if (!this.freqMap.has(evictKey)) {
        let newMin = Infinity;
        for (const freq of this.freqMap.values()) {
          if (freq < newMin) newMin = freq;
        }
        this.minFreq = newMin === Infinity ? 1 : newMin;
      }
    }
    return evictKey;
  }

  reset(): void {
    this.freqMap.clear();
    this.minFreq = 1;
  }
}

class TimeBasedStrategy<K, V> implements EvictionStrategy<K, V> {
  constructor(private ttlMs: number) {}

  private accessTimes = new Map<K, number>();

  onAccess(key: K): void {
    this.accessTimes.set(key, Date.now());
  }

  evictIfNeeded(cache: Cache<K, V>): K | null {
    const now = Date.now();
    let oldestKey: K | null = null;
    let oldestTime = Infinity;

    for (const [key, time] of this.accessTimes) {
      if (now - time > this.ttlMs) {
        cache.delete(key);
        this.accessTimes.delete(key);
        return key;
      }
      if (time < oldestTime) {
        oldestTime = time;
        oldestKey = key;
      }
    }

    if (cache.size() >= cache.getCapacity() && oldestKey) {
      cache.delete(oldestKey);
      this.accessTimes.delete(oldestKey);
      return oldestKey;
    }
    return null;
  }

  reset(): void {
    this.accessTimes.clear();
  }
}
```

## Registry Implementation

```typescript
class PolicyRegistryImpl<K, V> implements PolicyRegistry<K, V> {
  private factories = new Map<string, () => EvictionStrategy<K, V>>();

  register(name: string, factory: () => EvictionStrategy<K, V>): void {
    this.factories.set(name, factory);
  }

  deregister(name: string): boolean {
    return this.factories.delete(name);
  }

  has(name: string): boolean {
    return this.factories.has(name);
  }

  create(name: string): EvictionStrategy<K, V> | null {
    const factory = this.factories.get(name);
    return factory ? factory() : null;
  }
}
```

## Cache with Runtime Policy Switching

```typescript
class Cache<K, V> {
  private store = new Map<K, CacheEntry<V>>();
  private strategy: EvictionStrategy<K, V>;
  private capacity: number;

  constructor(
    capacity: number,
    registry: PolicyRegistryImpl<K, V>,
    initialPolicy: string
  ) {
    this.capacity = capacity;
    this.strategy = registry.create(initialPolicy)!;
  }

  setEvictionPolicy(policyName: string, registry: PolicyRegistryImpl<K, V>): void {
    const newStrategy = registry.create(policyName);
    if (!newStrategy) throw new Error(`Unknown policy: ${policyName}`);

    for (const [key, entry] of this.store) {
      newStrategy.onAccess(key);
    }
    this.strategy = newStrategy;
  }

  get(key: K): V | undefined {
    const entry = this.store.get(key);
    if (!entry) return undefined;

    entry.accessTime = Date.now();
    entry.accessCount++;
    this.strategy.onAccess(key);
    return entry.value;
  }

  set(key: K, value: V): void {
    if (this.store.has(key)) {
      const entry = this.store.get(key)!;
      entry.value = value;
      entry.accessTime = Date.now();
      this.strategy.onAccess(key);
      return;
    }

    this.strategy.evictIfNeeded(this);
    this.store.set(key, { value, accessTime: Date.now(), accessCount: 1 });
    this.strategy.onAccess(key);
  }

  delete(key: K): boolean {
    return this.store.delete(key);
  }

  size(): number { return this.store.size; }
  getCapacity(): number { return this.capacity; }
}
```

## Complete Usage Example

```typescript
const registry = new PolicyRegistryImpl<string, number>();

registry.register('lru', () => new LRUStrategy());
registry.register('lfu', () => new LFUStrategy());
registry.register('ttl-1min', () => new TimeBasedStrategy(60 * 1000));

const cache = new Cache(3, registry, 'lru');

cache.set('a', 1);
cache.set('b', 2);
cache.set('c', 3);
console.log(cache.get('a'), cache.get('b'));

cache.setEvictionPolicy('lfu', registry);
console.log('Switched to LFU');

cache.set('a', 1);
cache.set('d', 4);
console.log('a' in cache ? 'a retained' : 'a evicted');

const removed = registry.deregister('lru');
console.log('Deregistered lru:', removed);
console.log('Has lru:', registry.has('lru'));
```

