interface ConcurrencyPolicy {
  submit(job: () => void | Promise<void>): void;
  start(): void;
  stop(): void;
}

interface PolicyFactory {
  create(config?: Record<string, unknown>): ConcurrencyPolicy;
}

class PolicyRegistry {
  private factories = new Map<string, PolicyFactory>();

  register(name: string, factory: PolicyFactory): void {
    this.factories.set(name, factory);
  }

  create(name: string, config?: Record<string, unknown>): ConcurrencyPolicy {
    const factory = this.factories.get(name);
    if (!factory) throw new Error(`Unknown policy: ${name}`);
    return factory.create(config);
  }
}

// Built-in policies
class FixedWorkerPool implements ConcurrencyPolicy {
  private queue: Array<() => void> = [];
  private active = 0;

  constructor(private maxWorkers: number) {}

  submit(job: () => void): void {
    if (this.active < this.maxWorkers) {
      this.active++;
      job();
    } else {
      this.queue.push(job);
    }
  }

  start(): void { /* drain queue */ }
  stop(): void { /* reject queued */ }
}

// Usage
const registry = new PolicyRegistry();
registry.register('fixed', (config) => new FixedWorkerPool(config?.workers ?? 10));

const runner = new TaskRunner(registry);
runner.assign('POST /orders', 'fixed', { workers: 20 });
```

## Trade-off Discussion
| Aspect | FixedWorkerPool | WorkStealingPool | BandwidthLimitedPool |
|--------|-----------------|------------------|----------------------|
| Throughput | Predictable, bounded | High under skew | Rate-limited |
| Latency | Moderate queue delay | Low for varied work | Controlled but variable |
| Complexity | Low | High (deques, synchronization) | Medium (token bucket) |
| Deadlock Risk | Low if bounded queue | Medium (circular stealing) | Low |
| Memory | Bounded by queue size | Unbounded steals possible | Bounded by token rate |

