  private store = new Map<string, EvictionPolicyFactory<K>>();
  register(name: string, factory: EvictionPolicyFactory<K>) { this.store.set(name, factory); }
  create(name: string): EvictionPolicy<K> | null { const f = this.store.get(name); return f ? f() : null; }
}

class Cache<K, V> {
  private data = new Map<K, V>();
  private policy: EvictionPolicy<K> | null = null;
  constructor(private registry: Registry<K>, initialPolicy?: string) {
    if (initialPolicy) this.policy = registry.create(initialPolicy);
  }
  put(k: K, v: V) { this.data.set(k, v); this.policy?.onPut(k, v); if (this.policy) this.policy.evictIfNeeded(); }
  get(k: K): V | undefined { this.policy?.onGet(k); return this.data.get(k); }
  setPolicy(name: string) { const p = this.registry.create(name); if (p) this.policy = p; }
}
