```typescript
interface EvictionPolicy<K> {
  onAccess(key: K, cache: Map<K, unknown>): void;
  onInsert(key: K, value: unknown, cache: Map<K, unknown>): void;
  evict(cache: Map<K, unknown>): K | null;
}

class PolicyRegistry<K> {
  private byName = new Map<string, EvictionPolicy<K>>();

  register(name: string, policy: EvictionPolicy<K>): void {
    this.byName.set(name, policy);
  }

  get(name: string): EvictionPolicy<K> | undefined {
    return this.byName.get(name);
  }
}

class Cache<K, V> {
  private store = new Map<K, V>();
  private registry: PolicyRegistry<K>;
  private policy: EvictionPolicy<K>;

  constructor(policy: EvictionPolicy<K>, registry?: PolicyRegistry<K>) {
    this.policy = policy;
    this.registry = registry || new PolicyRegistry();
  }

  set(key: K, value: V): void {
    if (this.store.size >= this.capacity) {
      const evicted = this.policy.evict(this.store);
      if (evicted) this.store.delete(evicted);
    }
    this.policy.onInsert(key, value, this.store);
    this.store.set(key, value);
  }

  get(key: K): V | undefined {
    const value = this.store.get(key);
    if (value !== undefined) {
      this.policy.onAccess(key, value, this.store);
    }
    return value;
  }

  registerPolicy(name: string, policy: EvictionPolicy<K>): void {
    this.registry.register(name, policy);
  }
}

// Usage
const lruPolicy: EvictionPolicy<string> = {
  onAccess: (key, cache) => { /* update access order */ },
  onInsert: (key, value, cache) => { /* track insertion */ },
  evict: (cache) => { /* return least recently used key */ }
};

const cache = new Cache(lruPolicy);
cache.set('a', 1);
cache.get('a');
```

