  readonly name: string;
  evaluate(flagKey: string, context: FlagContext): boolean;
}

class BooleanEvaluator implements IFlagEvaluator {
  readonly name = 'boolean';
  evaluate(flagKey: string, context: FlagContext): boolean {
    return true; // or false based on flag configuration
  }
}

class PercentageOfTimeEvaluator implements IFlagEvaluator {
  readonly name = 'percentageOfTime';

  private readonly hash: (userId: string, flagKey: string) => number;

  constructor(private percentage: number) {
    this.hash = (userId: string, flagKey: string): number => {
      let hash = 0;
      const str = `${userId}:${flagKey}`;
      for (let i = 0; i < str.length; i++) {
        hash = ((hash << 5) - hash) + str.charCodeAt(i);
        hash |= 0;
      }
      return Math.abs(hash) % 100;
    };
  }

  evaluate(flagKey: string, context: FlagContext): boolean {
    const userId = context.userId ?? 'anonymous';
    return this.hash(userId, flagKey) < this.percentage;
  }
