  private flagOverrides = new Map<string, string>();
  private metrics: Array<{ flag: string; evaluator: string; result: boolean }> = [];

  register(evaluator: IFlagEvaluator): void {
    this.evaluators.set(evaluator.name, evaluator);
  }

  setFlagStrategy(flagKey: string, evaluatorName: string, config?: unknown): void {
    if (!this.evaluators.has(evaluatorName)) {
      throw new Error(`Evaluator '${evaluatorName}' not registered`);
    }
    this.flagOverrides.set(flagKey, evaluatorName);
  }

  isEnabled(flagKey: string, context: FlagContext = {}): boolean {
    const evaluatorName = this.flagOverrides.get(flagKey) ?? 'boolean';
    const evaluator = this.evaluators.get(evaluatorName)!;

    const result = evaluator.evaluate(flagKey, context);

    this.metrics.push({ flag: flagKey, evaluator: evaluatorName, result });

    return result;
  }

  getMetrics() {
    return [...this.metrics];
  }
}

