## Code Example
```javascript
type Context = { target: any; method: string; args: any[] };
interface Interceptor {
  name: string;
  intercept(ctx: Context, next: () => Promise<any>): Promise<any>;
}
class Registry {
  private map = new Map<string, () => Interceptor>();
  register(name: string, factory: () => Interceptor) { this.map.set(name, factory); }
  createChain(names: string[]): Interceptor[] { return names.map(n => this.map.get(n)!).filter(Boolean); }
}
function createProxy<T>(target: T, registry: Registry, perMethod: Map<string, string[]>): T {
  return new Proxy(target as any, {
    get(obj, prop: string) {
      const orig = (obj as any)[prop];
      if (typeof orig !== 'function') return orig;
      return (...args: any[]) => {
        const order = perMethod.get(prop) || [];
        const chain = registry.createChain(order);
        let idx = -1;
        const next = (): Promise<any> => {
          idx++;
          if (idx >= chain.length) return Promise.resolve(orig.apply(obj, args));
          const interceptor = chain[idx];
          return interceptor.intercept({ target: obj, method: prop, args }, next);
        };
        return next();
      };
    }
  });
}
```

