// types.ts
export interface Context {
  args: string[]
  env: Record<string, string>
}

export interface Command {
  name: string
  execute(ctx: Context): Promise<void>
  undo(ctx: Context): Promise<void>
}

export type CommandFactory = (name: string) => Command | Promise<Command>

// registry.ts
export class Registry {
  private factories = new Map<string, CommandFactory>()
  private commands = new Map<string, Command>()

  register(name: string, factory: CommandFactory): void {
    this.factories.set(name, factory)
  }

  async get(name: string): Promise<Command> {
    if (!this.commands.has(name)) {
      const factory = this.factories.get(name)
      if (!factory) throw new Error(`Command "${name}" not found`)
      this.commands.set(name, await factory(name))
    }
    return this.commands.get(name)!
  }
}

// macro.ts
export class Macro implements Command {
  name: string
  private commands: Command[]

  constructor(name: string, commands: Command[]) {
    this.name = name
    this.commands = commands
  }

  async execute(ctx: Context): Promise<void> {
    const executed: Command[] = []
    try {
      for (const cmd of this.commands) {
        await cmd.execute(ctx)
        executed.push(cmd)
      }
    } catch (err) {
      for (const cmd of executed.reverse()) {
        await cmd.undo(ctx)
      }
      throw err
    }
  }

  async undo(ctx: Context): Promise<void> {
    for (const cmd of this.commands.reverse()) {
      await cmd.undo(ctx)
    }
  }
}
```

