## Code Example

```typescript
interface Command {
  name: string;
  execute(args: string[], services: ServiceContainer): Promise<void>;
  help(): string;
}

class ServiceContainer {
  private map = new Map<string, any>();
  register<T>(name: string, value: T) { this.map.set(name, value); }
  resolve<T>(name: string): T | undefined { return this.map.get(name); }
}

class Registry {
  private cmds = new Map<string, Command>();
  register(cmd: Command) { this.cmds.set(cmd.name, cmd); }
  get(name: string): Command | undefined { return this.cmds.get(name); }
}

class Dispatcher {
  constructor(private registry: Registry, private services: ServiceContainer) {}
  async run(name: string, args: string[]) {
    const cmd = this.registry.get(name);
    if (!cmd) throw new Error(`Unknown command: ${name}`);
    try { await cmd.execute(args, this.services); } catch (err) {
      // isolate failure
      console.error(`Command ${name} failed`, err);
    }
  }
}
```

## Follow-up Questions

