function ReservoirStrategy(k: number): SamplingStrategy { return { name: 'Reservoir', shouldEmit: ctx => keepSample(ctx, k) } }
function ProbabilisticStrategy(p: number): SamplingStrategy { return { name: 'Probabilistic', shouldEmit: ctx => Math.random() < p } }
