Implement a pluggable Command pattern with a `Command` interface `{ execute(args: string[]): Promise<void> }` and a `CommandRegistry` with methods to `register(name, cmd)`, `get(name)`, `has(name)`, and `list()`. A lightweight `Dispatcher` parses user input and routes it to the appropriate command via the registry.

```typescript
interface Command {
  execute(args: string[]): Promise<void>;
}

class CommandRegistry {
  private commands = new Map<string, Command>();

  register(name: string, command: Command): void {
    this.commands.set(name, command);
  }

  get(name: string): Command | undefined {
    return this.commands.get(name);
  }

  has(name: string): boolean {
    return this.commands.has(name);
  }

  list(): string[] {
    return Array.from(this.commands.keys());
  }
}

class Dispatcher {
  constructor(private registry: CommandRegistry) {}

  async dispatch(input: string): Promise<void> {
    const [name, ...args] = input.trim().split(/\s+/);
    const command = this.registry.get(name);
    if (!command) throw new Error(`Unknown command: ${name}`);
    await command.execute(args);
  }
}

// Usage
const registry = new CommandRegistry();
registry.register('build', {
  execute: async (args) => console.log('Building:', args)
});
registry.register('test', {
  execute: async (args) => console.log('Testing:', args)
});

const dispatcher = new Dispatcher(registry);
await dispatcher.dispatch('build --watch');
```

