## Code Example

```javascript
interface Strategy {
  dispatch(queueId: string, tasks: any[]): any[]
}

class Registry<T> {
  private map = new Map<string, T>()
  register(name: string, value: T) { this.map.set(name, value) }
  get(name: string): T | undefined { return this.map.get(name) }
}

class QueueEngine {
  private currentStrategy: Strategy;
  constructor(private registry: Registry<Strategy>, initial: string) {
    const s = registry.get(initial); if (!s) throw new Error('unknown strategy')
    this.currentStrategy = s
  }
  swapStrategy(name: string) {
    const s = this.registry.get(name); if (s) this.currentStrategy = s
  }
  dispatch(queueId: string, tasks: any[]) {
    return this.currentStrategy.dispatch(queueId, tasks)
  }
}

// Usage
class RoundRobin implements Strategy { dispatch(q: string, t: any[]) { return t } }
class WorkStealing implements Strategy { dispatch(q: string, t: any[]) { return t } }
class PriorityBased implements Strategy { dispatch(q: string, t: any[]) { return t } }

const reg = new Registry<Strategy>()
reg.register('rr', new RoundRobin())
reg.register('ws', new WorkStealing())
reg.register('pb', new PriorityBased())

const engine = new QueueEngine(reg, 'rr')
engine.swapStrategy('pb')
```

