Define a `Backend` interface with `log(level, msg, ts) => Promise<void>` and an optional `flush()`. Use a `Registry` backed by `Map<string, BackendFactory>` to store backend factories. Backends buffer writes asynchronously to avoid blocking callers, flushing on interval or threshold. Each backend receives the log level directly, enabling per-backend filtering based on configured thresholds.

```typescript
type LogLevel = 'debug' | 'info' | 'warn' | 'error';

interface Backend {
  log(level: LogLevel, msg: string, ts?: number): Promise<void>;
  flush?(): Promise<void>;
}

type BackendFactory = () => Backend;

class Registry {
  private backends = new Map<string, BackendFactory>();

  register(name: string, factory: BackendFactory): void {
    if (this.backends.has(name)) {
      throw new Error(`Backend '${name}' is already registered`);
    }
    this.backends.set(name, factory);
  }

  create(name: string): Backend | undefined {
    return this.backends.get(name)?.();
  }
}

class ConsoleBackend implements Backend {
  async log(level, msg) {
    console[level](`[${level}] ${msg}`);
  }
}

class BufferedFileBackend implements Backend {
  private queue: string[] = [];
  private flushInterval: number;

  constructor(flushInterval = 5000) {
    this.flushInterval = flushInterval;
    setInterval(() => this.flush(), flushInterval);
  }

  async log(level, msg, ts = Date.now()) {
    this.queue.push(`[${ts}] [${level}] ${msg}`);
  }

  async flush() {
    if (this.queue.length === 0) return;
    const batch = this.queue.splice(0);
    await Bun.write('app.log', batch.join('\n') + '\n');
  }
}

// Usage
const registry = new Registry();
registry.register('console', () => new ConsoleBackend());
registry.register('file', () => new BufferedFileBackend());

const logger = registry.create('console');
await logger?.log('info', 'Application started');
```

