Use a `Policy` interface with an async `evaluate(ctx)` method returning `{ allowed: boolean, reason?: string }`. A `PolicyRegistry` maps policy names to factory functions. The engine executes policies in a configurable order with short-circuit evaluation—returning immediately on the first deny. Conflict resolution follows a deny-wins strategy: if any policy denies, the request is rejected regardless of other permits. Policies are scoped per resource, and decision caching with TTL-based invalidation prevents redundant evaluation of identical requests.

```typescript
interface PolicyContext {
  subject: { id: string; attributes: Record<string, unknown> };
  resource: { type: string; id: string; attributes: Record<string, unknown> };
  action: string;
}

interface Policy {
  name: string;
  evaluate(ctx: PolicyContext): Promise<Decision>;
}

type Decision = { allowed: boolean; reason?: string };
type Factory = () => Policy;

class PolicyRegistry {
  private policies = new Map<string, Factory>();

  register(name: string, factory: Factory): void {
    this.policies.set(name, factory);
  }

  create(name: string): Policy | undefined {
    return this.policies.get(name)?.();
  }

  list(): string[] {
    return [...this.policies.keys()];
  }
}

class PolicyEngine {
  private registry: PolicyRegistry;
  private order: string[] = [];
  private cache = new Map<string, { decision: Decision; expiresAt: number }>();
  private readonly defaultTtlMs = 60_000;

  constructor(registry: PolicyRegistry) {
    this.registry = registry;
  }

  setOrder(names: string[]): void {
    this.order = names;
  }

  private buildCacheKey(ctx: PolicyContext): string {
    return JSON.stringify(ctx);
  }

  async evaluate(ctx: PolicyContext): Promise<Decision> {
    const cacheKey = this.buildCacheKey(ctx);
    const cached = this.cache.get(cacheKey);

    if (cached && cached.expiresAt > Date.now()) {
      return cached.decision;
    }

    for (const name of this.order) {
      const policy = this.registry.create(name);
      if (!policy) continue;

      const decision = await policy.evaluate(ctx);
      if (!decision.allowed) {
        this.cache.set(cacheKey, { decision, expiresAt: Date.now() + this.defaultTtlMs });
        return decision;
      }
    }

    const result: Decision = { allowed: true };
    this.cache.set(cacheKey, { decision: result, expiresAt: Date.now() + this.defaultTtlMs });
    return result;
  }

  clearCache(): void {
    this.cache.clear();
  }
}

// Usage
const registry = new PolicyRegistry();
registry.register('rbac', () => new RoleBasedPolicy());
registry.register('abac', () => new AttributeBasedPolicy());
registry.register('timeWindow', () => new TimeWindowPolicy());

const engine = new PolicyEngine(registry);
engine.setOrder(['rbac', 'abac', 'timeWindow']);

const decision = await engine.evaluate({
  subject: { id: 'user-1', attributes: { role: 'admin' } },
  resource: { type: 'document', id: 'doc-42', attributes: {} },
  action: 'read'
});
```

