interface PaymentRequest {
  amount: number;
  currency: string;
  senderId: string;
  recipientId: string;
  metadata?: Record<string, unknown>;
}

interface ValidationError {
  code: string;
  message: string;
  field?: string;
  severity: 'error' | 'warning';
}

interface ValidationContext {
  transactionId: string;
  startTime: number;
  metadata: Record<string, unknown>;
}

type SyncValidator = (req: PaymentRequest, ctx: ValidationContext) => ValidationError[];
type AsyncValidator = (req: PaymentRequest, ctx: ValidationContext) => Promise<ValidationError[]>;

interface IValidationRule {
  name: string;
  order: number;
  validate: SyncValidator | AsyncValidator;
}

class ValidationRegistry {
  private rules = new Map<string, IValidationRule>();

  register(rule: IValidationRule): void {
    this.rules.set(rule.name, rule);
  }

  unregister(name: string): boolean {
    return this.rules.delete(name);
  }

  getOrderedRules(): IValidationRule[] {
    return Array.from(this.rules.values()).sort((a, b) => a.order - b.order);
  }
}

class ValidationPipeline {
  constructor(private registry: ValidationRegistry) {}

  async execute(request: PaymentRequest): Promise<ValidationError[]> {
    const context: ValidationContext = {
      transactionId: crypto.randomUUID(),
      startTime: Date.now(),
      metadata: {}
    };

    const allErrors: ValidationError[] = [];

    for (const rule of this.registry.getOrderedRules()) {
      const result = await rule.validate(request, context);
      allErrors.push(...result);
    }

    return allErrors;
  }
}

