class Cache<K, V> {
  private map = new Map<K, V>();
  private eviction: EvictionStrategy<K, V>;
  private refresh?: RefreshStrategy<K, V>;
  constructor(eviction: EvictionStrategy<K, V>, refresh?: RefreshStrategy<K, V>) {
    this.eviction = eviction; this.refresh = refresh;
  }
  set(key: K, value: V) {
    this.map.set(key, value);
    this.eviction.onPut(this, key, value, Date.now());
  }
  get(key: K): V | undefined {
    const v = this.map.get(key);
    if (v && this.refresh) this.refresh.onAccess(this, key, v, Date.now());
    return v;
  }
}
