```javascript
class Editor {
  constructor() { this.text = ''; }

  insert(pos, ch) {
    this.text = this.text.slice(0, pos) + ch + this.text.slice(pos);
  }

  delete(pos, len) {
    const removed = this.text.slice(pos, pos + len);
    this.text = this.text.slice(0, pos) + this.text.slice(pos + len);
    return removed;
  }
}

class InsertCommand {
  constructor(editor, pos, ch) {
    this.editor = editor;
    this.pos = pos;
    this.ch = ch;
  }

  execute() {
    this.editor.insert(this.pos, this.ch);
  }

  undo() {
    this.editor.delete(this.pos, 1);
  }
}

class History {
  constructor() {
    this.undoStack = [];
    this.redoStack = [];
  }

  execute(command) {
    command.execute();
    this.undoStack.push(command);
    this.redoStack = [];
  }

  undo() {
    if (this.undoStack.length === 0) return;
    const command = this.undoStack.pop();
    command.undo();
    this.redoStack.push(command);
  }
}

// Example: Insert 'A' at position 0, then undo
const editor = new Editor();
const history = new History();
const insertA = new InsertCommand(editor, 0, 'A');

history.execute(insertA); // text = 'A'
history.undo(); // text = ''
```

## Implementation Notes

- Commands capture all state needed for undo
- History maintains separate undo/redo stacks
- Each operation is atomic and reversible
- Position validation ensures safe operations

