type ExporterFactory = (config?: any) => MetricsExporter;

class MetricsRegistry {
  private factories = new Map<string, ExporterFactory>();
  private exporters = new Map<string, MetricsExporter>();

  register(name: string, factory: ExporterFactory): void {
    this.factories.set(name, factory);
  }

  create(name: string, config?: any): MetricsExporter | null {
    const factory = this.factories.get(name);
    if (!factory) return null;
    const exporter = factory(config);
    this.exporters.set(name, exporter);
    return exporter;
  }

  // Hot-reload: atomic swap with versioning
  replace(name: string, factory: ExporterFactory): boolean {
    const existing = this.factories.get(name);
    this.factories.set(name, factory);
    return !!existing;
  }
}

// Usage example
const registry = new MetricsRegistry();
registry.register('prometheus', cfg => new PrometheusExporter(cfg));
registry.register('datadog', cfg => new DatadogExporter(cfg));
registry.register('otel', cfg => new OpenTelemetryExporter(cfg));

// Runtime creation
const exporter = registry.create('prometheus', { port: 9090 });
await exporter.init();
await exporter.emit([{ name: 'latency', value: 42 }]);
```

