## Code Example (TypeScript)

```typescript
// Core types
interface MetricEvent {
  name: string;
  value: number;
  timestamp: number;
  tags?: Record<string, string>;
}

interface MetricSink {
  onEmit(event: MetricEvent): void | Promise<void>;
  shouldSample(event: MetricEvent): boolean;
  name: string;
}

// Sink Registry with runtime registration
class SinkRegistry {
  private sinks = new Map<string, MetricSink>();
  private mutex = new Mutex();

  async register(sink: MetricSink): Promise<void> {
    await this.mutex.acquire();
    try {
      if (this.sinks.has(sink.name)) {
        throw new Error(`Sink '${sink.name}' already registered`);
      }
      this.sinks.set(sink.name, sink);
    } finally {
      this.mutex.release();
    }
  }

  async unregister(name: string): Promise<boolean> {
    await this.mutex.acquire();
    try {
      return this.sinks.delete(name);
    } finally {
      this.mutex.release();
    }
  }

  get(name: string): MetricSink | undefined {
    return this.sinks.get(name);
  }

  list(): MetricSink[] {
    return Array.from(this.sinks.values());
  }

  get count(): number {
    return this.sinks.size;
  }
}

// Streaming pipeline with fan-out
class TelemetryPipeline {
  private registry: SinkRegistry;
  private eventQueue: AsyncQueue<MetricEvent>;
  private running = false;
  private workers: Task[] = [];

  constructor(registry: SinkRegistry, concurrency = 4) {
    this.registry = registry;
    this.eventQueue = new AsyncQueue();
    this.start(concurrency);
  }

  private start(concurrency: number): void {
    this.running = true;
    for (let i = 0; i < concurrency; i++) {
      this.workers.push(this.processLoop());
    }
  }

  private async* processLoop(): AsyncGenerator<void> {
    while (this.running) {
      const event = await this.eventQueue.dequeue();
      if (!event) continue;
      await this.fanOut(event);
    }
  }

  async emit(event: MetricEvent): Promise<void> {
    await this.eventQueue.enqueue(event);
  }

  private async fanOut(event: MetricEvent): Promise<void> {
    const sinks = this.registry.list();
    const results = sinks.map(async (sink) => {
      try {
        if (sink.shouldSample(event)) {
          await sink.onEmit(event);
        }
      } catch (err) {
        console.error(`Sink ${sink.name} failed:`, err);
      }
    });
    await Promise.allSettled(results);
  }

  async stop(): Promise<void> {
    this.running = false;
    await Promise.all(this.workers);
  }
}

// Concrete usage example with runtime sink registration
// 1. Create Prometheus sink implementation
class PrometheusSink implements MetricSink {
  name = 'prometheus';
  private counter = new Map<string, number>();

  shouldSample(event: MetricEvent): boolean {
    return event.name.startsWith('cpu.') || event.name.startsWith('memory.');
  }

  async onEmit(event: MetricEvent): Promise<void> {
    const key = `${event.name}:${JSON.stringify(event.tags || {})}`;
    this.counter.set(key, (this.counter.get(key) || 0) + event.value);
    console.log(`[Prometheus] ${key} = ${this.counter.get(key)}`);
  }
}

// 2. Create custom logging sink
class LoggingSink implements MetricSink {
  name = 'logging';

  shouldSample(_event: MetricEvent): boolean {
    return true; // Log everything
  }

  async onEmit(event: MetricEvent): Promise<void> {
    console.log(`[Log] ${event.name} = ${event.value}`, event.tags);
  }
}

// 3. Runtime registration flow
async function main() {
  const registry = new SinkRegistry();
  const pipeline = new TelemetryPipeline(registry);

  // Register initial sinks
  await registry.register(new LoggingSink());
  console.log('Registered logging sink');

  // Runtime: add Prometheus sink without stopping the pipeline
  const prometheus = new PrometheusSink();
  await registry.register(prometheus);
  console.log('Registered prometheus sink');

  // Emit metrics - both sinks receive events (with sampling)
  await pipeline.emit({ name: 'cpu.usage', value: 85, timestamp: Date.now(), tags: { host: 'a1' } });
  await pipeline.emit({ name: 'memory.usage', value: 4096, timestamp: Date.now() });
  await pipeline.emit({ name: 'request.count', value: 1, timestamp: Date.now() });

  // Runtime: unregister and swap sinks
  await registry.unregister('logging');
  await registry.register(new LoggingSink()); // re-register with new instance

  await pipeline.emit({ name: 'cpu.usage', value: 90, timestamp: Date.now() });

  await pipeline.stop();
}

main().catch(console.error);
```

## Key Design Decisions

1. **Mutex-protected registry** prevents race conditions during registration/unregistration
2. **Async queue with workers** provides backpressure handling and concurrent processing
3. **Promise.allSettled** ensures one sink failure doesn't break others (fault isolation)
4. **shouldSample per-sink** allows different backends to have independent sampling policies
5. **Atomic snapshot retrieval** via list() enables zero-downtime sink updates
